import{_ as o,o as a,c as t,a2 as r}from"./chunks/framework.BYlK8ftn.js";const u=JSON.parse('{"title":"Deployment","description":"","frontmatter":{},"headers":[],"relativePath":"operations/deployment.md","filePath":"operations/deployment.md","lastUpdated":1781956058000}'),l={name:"operations/deployment.md"};function s(d,e,i,n,c,p){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="deployment" tabindex="-1">Deployment <a class="header-anchor" href="#deployment" aria-label="Permalink to &quot;Deployment&quot;">​</a></h1><p>Korovany has two independent publish targets, both driven by GitHub Actions on pushes to <code>main</code>.</p><h2 id="_1-the-app-→-cloudflare-pages" tabindex="-1">1. The app → Cloudflare Pages <a class="header-anchor" href="#_1-the-app-→-cloudflare-pages" aria-label="Permalink to &quot;1. The app → Cloudflare Pages&quot;">​</a></h2><ul><li>Workflow: <code>.github/workflows/deploy.yml</code></li><li>Builds the SPA (<code>npm run build</code>) and deploys <code>./dist</code> to Cloudflare Pages (project <code>korovany</code>) via <code>cloudflare/wrangler-action</code>.</li><li>Custom domain: <strong><a href="https://korovany.aimost.pl/" target="_blank" rel="noreferrer">https://korovany.aimost.pl/</a></strong> (also reachable at <code>https://korovany.pages.dev</code>).</li><li>Requires the GitHub Actions secrets <code>CLOUDFLARE_API_TOKEN</code> and <code>CLOUDFLARE_ACCOUNT_ID</code> — see <a href="/korovany/operations/cloudflare-deploy">Cloudflare credentials</a>. The deploy step skips gracefully until those exist, then activates automatically.</li></ul><h2 id="_2-the-docs-→-github-pages" tabindex="-1">2. The docs → GitHub Pages <a class="header-anchor" href="#_2-the-docs-→-github-pages" aria-label="Permalink to &quot;2. The docs → GitHub Pages&quot;">​</a></h2><ul><li>Workflow: <code>.github/workflows/docs.yml</code></li><li>Builds this VitePress site (<code>npm run docs:build</code>) and deploys it to GitHub Pages at <strong><a href="https://fl0p.github.io/korovany/" target="_blank" rel="noreferrer">https://fl0p.github.io/korovany/</a></strong>.</li><li>Pages is enabled by the workflow itself (<code>actions/configure-pages</code> with <code>enablement: true</code>); no manual dashboard step is required.</li></ul><h2 id="triggering-a-deploy" tabindex="-1">Triggering a deploy <a class="header-anchor" href="#triggering-a-deploy" aria-label="Permalink to &quot;Triggering a deploy&quot;">​</a></h2><p>Both run on every push to <code>main</code>. The app workflow also supports manual <code>workflow_dispatch</code> from the <strong>Actions</strong> tab once secrets are present.</p>',8)])])}const g=o(l,[["render",s]]);export{u as __pageData,g as default};
